package travelcare_agent.evaluation; import org.springframework.stereotype.Component; import travelcare_agent.evaluation.entity.*; import travelcare_agent.evaluation.scoring.ScoreResult; import java.nio.file.*; import java.time.*; import java.util.*;
@Component public class EvaluationRunReportWriter {private final Path root;public EvaluationRunReportWriter(){this(Path.of("target","evaluation","runs"));} public EvaluationRunReportWriter(Path root){this.root=root;} public Path path(Long id){return root.resolve(id+"_report.md");} public Path write(EvaluationRun run,EvaluationDataset dataset,List<EvaluationCase> cases,List<EvaluationCaseResult> results,Map<Long,List<ScoreResult>> scores,Clock clock)throws Exception{Files.createDirectories(root);Map<Long,EvaluationCase> byId=new HashMap<>();cases.forEach(c->byId.put(c.getId(),c));StringBuilder b=new StringBuilder("# Evaluation Run ").append(run.getId()).append("\n\n");line(b,"Run ID",run.getId());line(b,"Dataset key",dataset.getDatasetKey());line(b,"Dataset version",run.getDatasetVersion());line(b,"Provider mode",run.getProviderMode());line(b,"Prompt stub version",run.getPromptStubVersion());line(b,"Run status",run.getStatus());line(b,"Total count",run.getTotalCount());line(b,"Passed count",run.getPassedCount());line(b,"Failed count",run.getFailedCount());line(b,"Error count",run.getErrorCount());line(b,"Skipped count",run.getSkippedCount());line(b,"Started at",run.getStartedAt());line(b,"Finished at",run.getFinishedAt());line(b,"Report generated at",LocalDateTime.now(clock));for(EvaluationCaseResult r:results){EvaluationCase c=byId.get(r.getCaseId());b.append("\n## Case ").append(r.getCaseKey()).append("\n\n");line(b,"caseKey",r.getCaseKey());line(b,"caseName",c==null?null:c.getName());line(b,"sourceTraceId",r.getSourceTraceId());line(b,"dryRunTraceId",r.getDryRunTraceId());line(b,"diffId",r.getDiffId());line(b,"status",r.getStatus());line(b,"riskLevel",r.getRiskLevel());line(b,"failureReason",r.getFailureReason());b.append("- scorer results: `").append(scores.getOrDefault(r.getCaseId(),List.of())).append("`\n");}Files.writeString(path(run.getId()),b.toString());return path(run.getId());} public String read(Long id)throws Exception{return Files.readString(path(id));}private void line(StringBuilder b,String k,Object v){b.append("- ").append(k).append(": ").append(v==null?"":v).append("\n");}}
